      "transcription_config?: { client_state?: string; command_id?: string; transcription_engine?: 'Google' | 'Telnyx' | 'Deepgram' | 'Azure' | 'A' | 'B'; transcription_engine_config?: { enable_speaker_diarization?: boolean; hints?: string[]; interim_results?: boolean; language?: google_transcription_language; max_speaker_count?: number; min_speaker_count?: number; model?: string; profanity_filter?: boolean; speech_context?: object[]; transcription_engine?: 'Google'; use_enhanced?: boolean; } | { language?: telnyx_transcription_language; transcription_engine?: 'Telnyx'; transcription_model?: 'openai/whisper-tiny' | 'openai/whisper-large-v3-turbo'; } | { region: 'australiaeast' | 'centralindia' | 'eastus' | 'northcentralus' | 'westeurope' | 'westus2'; transcription_engine: 'Azure'; api_key_ref?: string; language?: string; } | { enable_speaker_diarization?: boolean; hints?: string[]; interim_results?: boolean; language?: google_transcription_language; max_speaker_count?: number; min_speaker_count?: number; model?: string; profanity_filter?: boolean; speech_context?: object[]; transcription_engine?: 'A'; use_enhanced?: boolean; } | { language?: telnyx_transcription_language; transcription_engine?: 'B'; transcription_model?: 'openai/whisper-tiny' | 'openai/whisper-large-v3-turbo'; } | { transcription_engine: 'deepgram/nova-2'; transcription_model: 'deepgram/nova-2'; interim_results?: boolean; keywords_boosting?: object; language?: string; utterance_end_ms?: number; } | { transcription_engine: 'deepgram/nova-3'; transcription_model: 'deepgram/nova-3'; interim_results?: boolean; keywords_boosting?: object; language?: string; utterance_end_ms?: number; }; transcription_tracks?: string; };",
