    name: 'start_streaming',
    endpoint: '/calls/{call_control_id}/actions/streaming_start',
    httpMethod: 'post',
    summary: 'Streaming start',
    description:
      'Start streaming the media from a call to a specific WebSocket address or Dialogflow connection in near-realtime. Audio will be delivered as base64-encoded RTP payload (raw audio), wrapped in JSON payloads.\n\nPlease find more details about media streaming messages specification under the [link](https://developers.telnyx.com/docs/voice/programmable-voice/media-streaming).',
    stainlessPath: '(resource) calls.actions > (method) start_streaming',
