    markdown:
      "## retrieve\n\n`client.credentialConnections.retrieve(id: string): { data?: credential_connection; }`\n\n**get** `/credential_connections/{id}`\n\nRetrieves the details of an existing credential connection.\n\n### Parameters\n\n- `id: string`\n\n### Returns\n\n- `{ data?: { id?: string; active?: boolean; anchorsite_override?: anchorsite_override; android_push_credential_id?: string; call_cost_in_webhooks?: boolean; connection_name?: string; created_at?: string; default_on_hold_comfort_noise_enabled?: boolean; dtmf_type?: dtmf_type; encode_contact_header_enabled?: boolean; encrypted_media?: encrypted_media; inbound?: credential_inbound; ios_push_credential_id?: string; jitter_buffer?: connection_jitter_buffer; noise_suppression?: 'inbound' | 'outbound' | 'both' | 'disabled'; noise_suppression_details?: connection_noise_suppression_details; onnet_t38_passthrough_enabled?: boolean; outbound?: credential_outbound; password?: string; record_type?: string; rtcp_settings?: connection_rtcp_settings; sip_uri_calling_preference?: 'disabled' | 'unrestricted' | 'internal'; tags?: string[]; updated_at?: string; user_name?: string; webhook_api_version?: '1' | '2'; webhook_event_failover_url?: string; webhook_event_url?: string; webhook_timeout_secs?: number; }; }`\n\n  - `data?: { id?: string; active?: boolean; anchorsite_override?: string; android_push_credential_id?: string; call_cost_in_webhooks?: boolean; connection_name?: string; created_at?: string; default_on_hold_comfort_noise_enabled?: boolean; dtmf_type?: 'RFC 2833' | 'Inband' | 'SIP INFO'; encode_contact_header_enabled?: boolean; encrypted_media?: 'SRTP'; inbound?: { ani_number_format?: '+E.164' | 'E.164' | '+E.164-national' | 'E.164-national'; channel_limit?: number; codecs?: string[]; default_routing_method?: 'sequential' | 'round-robin'; dnis_number_format?: '+e164' | 'e164' | 'national' | 'sip_username'; generate_ringback_tone?: boolean; isup_headers_enabled?: boolean; prack_enabled?: boolean; shaken_stir_enabled?: boolean; simultaneous_ringing?: 'disabled' | 'enabled'; sip_compact_headers_enabled?: boolean; timeout_1xx_secs?: number; timeout_2xx_secs?: number; }; ios_push_credential_id?: string; jitter_buffer?: { enable_jitter_buffer?: boolean; jitterbuffer_msec_max?: number; jitterbuffer_msec_min?: number; }; noise_suppression?: 'inbound' | 'outbound' | 'both' | 'disabled'; noise_suppression_details?: { attenuation_limit?: number; engine?: string; }; onnet_t38_passthrough_enabled?: boolean; outbound?: { ani_override?: string; ani_override_type?: 'always' | 'normal' | 'emergency'; call_parking_enabled?: boolean; channel_limit?: number; generate_ringback_tone?: boolean; instant_ringback_enabled?: boolean; localization?: string; outbound_voice_profile_id?: string; t38_reinvite_source?: 'telnyx' | 'customer' | 'disabled' | 'passthru' | 'caller-passthru' | 'callee-passthru'; }; password?: string; record_type?: string; rtcp_settings?: { capture_enabled?: boolean; port?: 'rtcp-mux' | 'rtp+1'; report_frequency_secs?: number; }; sip_uri_calling_preference?: 'disabled' | 'unrestricted' | 'internal'; tags?: string[]; updated_at?: string; user_name?: string; webhook_api_version?: '1' | '2'; webhook_event_failover_url?: string; webhook_event_url?: string; webhook_timeout_secs?: number; }`\n\n### Example\n\n```typescript\nimport Telnyx from 'telnyx';\n\nconst client = new Telnyx();\n\nconst credentialConnection = await client.credentialConnections.retrieve('id');\n\nconsole.log(credentialConnection);\n```",
